sys_script.script:
(function executeRule(current, previous /*null when async*/) {

	//THIS BR HAS BEEN DEACTIVATED TO PREVENT LOSS OF DATA ON PARAMETER DELETION.

	var paramValue, debugLogMsg;
	var currentActionParamID = current.getUniqueValue(); //The current "Configured Action Parameter"
	var grConfiguredParam = new GlideRecord('x_taniu_tan_core_configured_action_parameter');

	grConfiguredParam.addQuery('package_parameter', currentActionParamID);
	grConfiguredParam.query();

	while (grConfiguredParam.next()) {
		paramValue = grConfiguredParam.getValue('value');

		debugLogMsg = 'The Configured Action Parameter with sys_id ' +
			grConfiguredParam.getUniqueValue();
		if (paramValue) {
			debugLogMsg += ' and configured value ' + paramValue;
		}
		debugLogMsg += ' has been automatically deleted, as the associated Tanium Action ' +
			'Package Parameter has also been deleted.';

		grConfiguredParam.deleteRecord();
		gs.debug(debugLogMsg);
	}

})(current, previous);
